void doFastMemoryTest(void) {
#if defined(HAVE_PROC_MAPS)
    if (server.memcheck_enabled) {
#if defined(VALKEY_ADDRESS_SANITIZER)
        /* AddressSanitizer creates anonymous writable shadow mappings that are
         * not ordinary application memory. The crash-time preserving memory
         * test scans anonymous mappings from /proc/self/maps, so testing those
         * regions in an ASan build can make the crash reporter itself trip ASan
         * before it finishes reporting the original assertion or crash. */
        serverLogRaw(LL_WARNING | LL_RAW, "\n------ FAST MEMORY TEST SKIPPED (AddressSanitizer) ------\n");
#else
        /* Test memory */
        serverLogRaw(LL_WARNING | LL_RAW, "\n------ FAST MEMORY TEST ------\n");
        killThreads();
        if (memtest_test_linux_anonymous_maps()) {
            serverLogRaw(LL_WARNING | LL_RAW, "!!! MEMORY ERROR DETECTED! Check your memory ASAP !!!\n");
        } else {
            serverLogRaw(LL_WARNING | LL_RAW, "Fast memory test PASSED, however your memory can still be broken. "
                                              "Please run a memory test for several hours if possible.\n");
        }
#endif
    }
#endif /* HAVE_PROC_MAPS */
}

